	this._sideEffectsStateGraph = undefined;
	/** @type {ConnectionState | undefined} */
	this._sideEffectsStateValue = undefined;
	/**
	 * @private
	 * @type {CodeGenerationResultData}
	 */
	this._codeGeneratorData = new Map();
}

